import type { Credentials } from './types'

/**
 * Parse a CodeMobile QR launch URL into credentials.
 *
 * Expected format (generated by EchoFlow Desktop H5 Access settings):
 *   http://192.168.1.10:3456/?serverUrl=http%3A%2F%2F192.168.1.10%3A3456&h5Token=h5_abc123
 *
 * Returns null when the data is not a valid CodeMobile launch URL.
 */
export function parseLaunchUrl(qrData: string): Credentials | null {
  const trimmed = qrData.trim()
  if (!trimmed) return null

  let parsed: URL
  try {
    parsed = new URL(trimmed)
  } catch {
    return null
  }

  if (parsed.protocol !== 'http:' && parsed.protocol !== 'https:') {
    return null
  }

  const serverUrl = parsed.searchParams.get('serverUrl')
  const h5Token = parsed.searchParams.get('h5Token')

  if (!serverUrl || !h5Token) return null
  if (!h5Token.trim()) return null

  // Validate serverUrl is also a valid HTTP(S) URL
  try {
    const serverParsed = new URL(serverUrl)
    if (serverParsed.protocol !== 'http:' && serverParsed.protocol !== 'https:') {
      return null
    }
  } catch {
    return null
  }

  return { serverUrl: serverUrl.trim(), h5Token: h5Token.trim() }
}
